# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import os
import sqlite3
from typing import Optional

class FileAccessControl:
    def __init__(self, db_name):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()

    def has_permission(self, username: str, file_path: str) -> bool:
        self.cursor.execute("SELECT access_level FROM users WHERE username = ?", (username,))
        user_access_level = self.cursor.fetchone()
        
        if not user_access_level:
            return False
        
        self.cursor.execute("""
            SELECT permission
            FROM files_permissions
            WHERE access_level = ? AND file_path = ?
        """, (user_access_level[0], os.path.abspath(file_path)))
        
        permission = self.cursor.fetchone()
        
        return bool(permission)

    def read_file(self, username: str, file_path: str) -> Optional[str]:
        if not self.has_permission(username, file_path):
            raise PermissionError(f"User {username} does not have permission to access file at {file_path}")
        
        try:
            with open(file_path, 'r') as f:
                return f.read()
        except FileNotFoundError:
            return None

